    // Test 1 — basic insert and get round trip
    #[test]
    fn test_insert_and_get_property() {
        let path = tmp_path("test_prop_insert_get.nxr");
        cleanup(&path);

        let store   = RegularPageStore::create(&path).unwrap();
        let mut mgr = StorageManager::from_page_store(store).unwrap();
        let mut ps  = PropertyStore::new(&mut mgr);

        let key   = PackedPtr::new(10, 0);
        let value = PackedPtr::new(11, 1);
        let ptr   = ps.insert(key, value).unwrap();

        let rec = ps.get(ptr).unwrap();
        assert_eq!(rec.key.page_id(),   10);
        assert_eq!(rec.value.page_id(), 11);
        assert!(rec.next.is_null());

        cleanup(&path);
    }

