        let mut mgr = StorageManager::from_page_store(store).unwrap();
        let mut ps  = PropertyStore::new(&mut mgr);

        let ptr0 = ps.insert(PackedPtr::new(1, 0), PackedPtr::new(2, 0)).unwrap();
        let _    = ps.insert(PackedPtr::new(3, 0), PackedPtr::new(4, 0)).unwrap();

